import { useAuthStore } from '../stores/auth'

// --- Types ---

export interface WhatsAppPhoneNumber {
  id: string
  org_id: string
  phone_number: string
  display_name: string
  waba_id: string
  verified: boolean
  created_at: string
  updated_at: string
}

export interface WhatsAppPhoneNumberListResponse {
  phone_numbers: WhatsAppPhoneNumber[]
  total: number
  limit: number
  offset: number
}

export type WhatsAppCallDirection = 'inbound' | 'outbound'
export type WhatsAppCallState = 'ringing' | 'connected' | 'ended'

export interface WhatsAppCall {
  id: string
  org_id: string
  call_id: string
  phone_number_id: string
  direction: WhatsAppCallDirection
  state: WhatsAppCallState
  caller: string
  callee: string
  from?: string
  to?: string
  sdp_offer?: string
  sdp_answer?: string
  started_at?: string
  ended_at?: string
  duration_seconds?: number
  created_at: string
  updated_at: string
}

export interface WhatsAppCallListResponse {
  calls: WhatsAppCall[]
  total: number
  limit: number
  offset: number
}

export type BridgeState = 'initializing' | 'active' | 'failed' | 'closed'

export interface WhatsAppBridge {
  id: string
  org_id: string
  call_id: string
  livekit_room: string
  bridge_state: BridgeState
  voice_session_id?: string
  sdp_offer?: string
  sdp_answer?: string
  metadata?: string
  created_at: string
  updated_at: string
  closed_at?: string
}

export interface CreatePhoneNumberRequest {
  phone_number: string
  display_name?: string
  waba_id: string
}

export interface InitiateCallRequest {
  phone_number_id: string
  callee: string
}

export interface WebhookEvent {
  id: string
  phone_number_id: string
  event_type: 'call_started' | 'call_connected' | 'call_ended'
  call_id: string
  timestamp: string
  detail?: string
}

// --- HTTP helper ---

async function authFetch(path: string, init?: RequestInit): Promise<Response> {
  const auth = useAuthStore()
  if (!auth.accessToken) {
    throw new Error('Not authenticated')
  }
  const base = import.meta.env.VITE_API_BASE_URL ?? '/api/v1'
  return fetch(base + path, {
    ...init,
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${auth.accessToken}`,
      ...init?.headers,
    },
  })
}

async function handleResponse<T>(res: Response): Promise<T> {
  if (!res.ok) {
    const err = await res.json().catch(() => ({ message: res.statusText }))
    throw new Error((err as { message?: string }).message ?? `Request failed with status ${res.status}`)
  }
  if (res.status === 204) return undefined as T
  return res.json() as Promise<T>
}

function whatsappBase(orgId: string): string {
  return `/orgs/${encodeURIComponent(orgId)}/whatsapp`
}

// --- Phone number API ---

export async function listPhoneNumbers(
  orgId: string,
  limit = 20,
  offset = 0,
): Promise<WhatsAppPhoneNumberListResponse> {
  const res = await authFetch(
    `${whatsappBase(orgId)}/phone-numbers?limit=${limit}&offset=${offset}`,
  )
  return handleResponse<WhatsAppPhoneNumberListResponse>(res)
}

export async function createPhoneNumber(
  orgId: string,
  data: CreatePhoneNumberRequest,
): Promise<WhatsAppPhoneNumber> {
  const res = await authFetch(`${whatsappBase(orgId)}/phone-numbers`, {
    method: 'POST',
    body: JSON.stringify(data),
  })
  return handleResponse<WhatsAppPhoneNumber>(res)
}

export async function deletePhoneNumber(orgId: string, phoneId: string): Promise<void> {
  const res = await authFetch(`${whatsappBase(orgId)}/phone-numbers/${encodeURIComponent(phoneId)}`, {
    method: 'DELETE',
  })
  return handleResponse<void>(res)
}

// --- Calls API ---

export async function listCalls(
  orgId: string,
  limit = 20,
  offset = 0,
): Promise<WhatsAppCallListResponse> {
  const res = await authFetch(
    `${whatsappBase(orgId)}/calls?limit=${limit}&offset=${offset}`,
  )
  return handleResponse<WhatsAppCallListResponse>(res)
}

export async function getCall(orgId: string, callId: string): Promise<WhatsAppCall> {
  const res = await authFetch(`${whatsappBase(orgId)}/calls/${encodeURIComponent(callId)}`)
  return handleResponse<WhatsAppCall>(res)
}

export async function initiateCall(
  orgId: string,
  data: InitiateCallRequest,
): Promise<WhatsAppCall> {
  const res = await authFetch(`${whatsappBase(orgId)}/calls`, {
    method: 'POST',
    body: JSON.stringify(data),
  })
  return handleResponse<WhatsAppCall>(res)
}

export async function endCall(orgId: string, callId: string): Promise<WhatsAppCall> {
  const res = await authFetch(`${whatsappBase(orgId)}/calls/${encodeURIComponent(callId)}`, {
    method: 'PATCH',
    body: JSON.stringify({ state: 'ended' }),
  })
  return handleResponse<WhatsAppCall>(res)
}

// --- Bridge API ---

export async function getBridge(orgId: string, callId: string): Promise<WhatsAppBridge> {
  const res = await authFetch(`${whatsappBase(orgId)}/calls/${encodeURIComponent(callId)}/bridge`)
  const body = await handleResponse<{ bridge: WhatsAppBridge }>(res)
  return body.bridge
}

export async function listActiveBridges(orgId: string): Promise<WhatsAppBridge[]> {
  const res = await authFetch(`${whatsappBase(orgId)}/bridges`)
  return handleResponse<WhatsAppBridge[]>(res)
}

import { useAuthStore } from '../stores/auth'

export type VoiceSessionState = 'created' | 'active' | 'ended'
export type VoiceSpeaker = 'agent' | 'user'

export interface VoiceSession {
  id: string
  org_id: string
  user_id?: string
  stranger_id?: string
  livekit_room: string
  state: VoiceSessionState
  started_at?: string
  ended_at?: string
  call_duration_seconds?: number
  created_at: string
  updated_at: string
}

export interface VoiceTurn {
  id: string
  session_id: string
  org_id: string
  speaker: VoiceSpeaker
  transcript: string
  started_at: string
  ended_at?: string
  created_at: string
}

export interface CreateVoiceSessionRequest {
  livekit_room?: string
  user_id?: string
  stranger_id?: string
}

export interface UpdateVoiceSessionStateRequest {
  state: VoiceSessionState
}

export interface AppendVoiceTurnRequest {
  speaker: VoiceSpeaker
  transcript: string
  started_at: string
  ended_at?: string
}

export interface VoiceSessionListResponse {
  sessions: VoiceSession[]
  total: number
  limit: number
  offset: number
}

export interface VoiceTurnListResponse {
  session_id: string
  turns: VoiceTurn[]
}

export interface VoiceTokenResponse {
  token: string
  url: string
}

const API_BASE = import.meta.env.VITE_API_BASE_URL ?? '/api/v1'

async function authFetch(path: string, init?: RequestInit): Promise<Response> {
  const auth = useAuthStore()
  if (!auth.accessToken) {
    throw new Error('Not authenticated')
  }
  return fetch(API_BASE + path, {
    ...init,
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${auth.accessToken}`,
      ...init?.headers,
    },
  })
}

export async function listVoiceSessions(
  orgId: string,
  limit = 20,
  offset = 0,
): Promise<VoiceSessionListResponse> {
  const res = await authFetch(
    `/orgs/${encodeURIComponent(orgId)}/voice-sessions?limit=${limit}&offset=${offset}`,
  )
  if (!res.ok) throw new Error(`listVoiceSessions failed: ${res.status}`)
  return res.json()
}

export async function getVoiceSession(orgId: string, sessionId: string): Promise<VoiceSession> {
  const res = await authFetch(`/orgs/${encodeURIComponent(orgId)}/voice-sessions/${encodeURIComponent(sessionId)}`)
  if (!res.ok) throw new Error(`getVoiceSession failed: ${res.status}`)
  return res.json()
}

export async function createVoiceSession(
  orgId: string,
  req: CreateVoiceSessionRequest,
): Promise<VoiceSession> {
  const res = await authFetch(`/orgs/${encodeURIComponent(orgId)}/voice-sessions`, {
    method: 'POST',
    body: JSON.stringify(req),
  })
  if (!res.ok) throw new Error(`createVoiceSession failed: ${res.status}`)
  return res.json()
}

export async function updateVoiceSessionState(
  orgId: string,
  sessionId: string,
  state: VoiceSessionState,
): Promise<VoiceSession> {
  const res = await authFetch(`/orgs/${encodeURIComponent(orgId)}/voice-sessions/${encodeURIComponent(sessionId)}`, {
    method: 'PATCH',
    body: JSON.stringify({ state } satisfies UpdateVoiceSessionStateRequest),
  })
  if (!res.ok) throw new Error(`updateVoiceSessionState failed: ${res.status}`)
  return res.json()
}

export async function generateVoiceToken(
  orgId: string,
  sessionId: string,
): Promise<VoiceTokenResponse> {
  const res = await authFetch(`/orgs/${encodeURIComponent(orgId)}/voice-sessions/${encodeURIComponent(sessionId)}/token`, {
    method: 'POST',
  })
  if (!res.ok) throw new Error(`generateVoiceToken failed: ${res.status}`)
  return res.json()
}

export async function listVoiceTurns(
  orgId: string,
  sessionId: string,
): Promise<VoiceTurnListResponse> {
  const res = await authFetch(`/orgs/${encodeURIComponent(orgId)}/voice-sessions/${encodeURIComponent(sessionId)}/turns`)
  if (!res.ok) throw new Error(`listVoiceTurns failed: ${res.status}`)
  return res.json()
}

export async function appendVoiceTurn(
  orgId: string,
  sessionId: string,
  req: AppendVoiceTurnRequest,
): Promise<VoiceTurn> {
  const res = await authFetch(`/orgs/${encodeURIComponent(orgId)}/voice-sessions/${encodeURIComponent(sessionId)}/turns`, {
    method: 'POST',
    body: JSON.stringify(req),
  })
  if (!res.ok) throw new Error(`appendVoiceTurn failed: ${res.status}`)
  return res.json()
}

// Package testutil provides shared helpers for Go tests including database containers,
// fixture factories, and gRPC stub implementations.
package testutil

import (
	"context"
	"database/sql"
	"fmt"
	"path/filepath"
	"runtime"
	"testing"
	"time"

	"github.com/jackc/pgx/v5/pgxpool"
	_ "github.com/lib/pq"
	"github.com/pressly/goose/v3"
	"github.com/stretchr/testify/require"
	"github.com/testcontainers/testcontainers-go"
	"github.com/testcontainers/testcontainers-go/wait"
)

// NewTestDB spins up a real PostgreSQL container using pgvector, runs all migrations,
// and returns a pool. Container is terminated when t ends.
func NewTestDB(t *testing.T) *pgxpool.Pool {
	t.Helper()
	ctx := context.Background()

	req := testcontainers.ContainerRequest{
		Image:        "pgvector/pgvector:pg17",
		ExposedPorts: []string{"5432/tcp"},
		Env: map[string]string{
			"POSTGRES_USER":     "raven_test",
			"POSTGRES_PASSWORD": "raven_test_pass",
			"POSTGRES_DB":       "raven_test",
		},
		WaitingFor: wait.ForLog("database system is ready to accept connections").
			WithOccurrence(2).
			WithStartupTimeout(90 * time.Second),
	}

	container, err := testcontainers.GenericContainer(ctx, testcontainers.GenericContainerRequest{
		ContainerRequest: req,
		Started:          true,
	})
	require.NoError(t, err, "start postgres container")
	t.Cleanup(func() { _ = container.Terminate(ctx) })

	host, err := container.Host(ctx)
	require.NoError(t, err)

	port, err := container.MappedPort(ctx, "5432")
	require.NoError(t, err)

	connStr := fmt.Sprintf(
		"host=%s port=%s user=raven_test password=raven_test_pass dbname=raven_test sslmode=disable",
		host, port.Port(),
	)

	// Wait for DB to be fully ready.
	var db *sql.DB
	db, err = sql.Open("postgres", connStr)
	require.NoError(t, err)
	for i := 0; i < 30; i++ {
		if pingErr := db.PingContext(ctx); pingErr == nil {
			break
		}
		time.Sleep(time.Second)
	}
	require.NoError(t, db.PingContext(ctx), "database must be reachable")

	RunMigrations(t, db)
	_ = db.Close()

	pgxConnStr := fmt.Sprintf(
		"postgres://raven_test:raven_test_pass@%s:%s/raven_test?sslmode=disable",
		host, port.Port(),
	)
	pool, err := pgxpool.New(ctx, pgxConnStr)
	require.NoError(t, err)
	t.Cleanup(pool.Close)

	return pool
}

// RunMigrations applies all goose migrations from the repo migrations/ dir.
func RunMigrations(t *testing.T, db *sql.DB) {
	t.Helper()

	// Resolve migrations dir relative to this file: internal/testutil/ -> repo root/migrations/
	_, filename, _, ok := runtime.Caller(0)
	if !ok {
		t.Fatal("runtime.Caller failed to retrieve file path")
	}
	migrationsDir := filepath.Join(filepath.Dir(filename), "..", "..", "migrations")

	if err := goose.SetDialect("postgres"); err != nil {
		t.Fatalf("goose.SetDialect: %v", err)
	}
	if err := goose.Up(db, migrationsDir); err != nil {
		t.Fatalf("goose.Up: %v", err)
	}
}

