import { defineStore } from 'pinia'
import { ref } from 'vue'
import { filter } from 'remeda'
import {
  listPhoneNumbers,
  createPhoneNumber,
  deletePhoneNumber,
  listCalls,
  getCall,
  initiateCall,
  updateCallState,
  getBridgeStatus,
  listActiveBridges,
  type WhatsAppPhoneNumber,
  type WhatsAppCall,
  type WhatsAppBridge,
  type CreatePhoneNumberRequest,
  type InitiateCallRequest,
  type CallState,
} from '../api/whatsapp'

export const useWhatsAppStore = defineStore('whatsapp', () => {
  // --- Phone numbers ---
  const phoneNumbers = ref<WhatsAppPhoneNumber[]>([])
  const phoneTotal = ref(0)

  // --- Calls ---
  const calls = ref<WhatsAppCall[]>([])
  const callTotal = ref(0)
  const activeCall = ref<WhatsAppCall | null>(null)

  // --- Bridges ---
  const bridges = ref<WhatsAppBridge[]>([])
  const currentBridge = ref<WhatsAppBridge | null>(null)

  // --- Shared state ---
  const loading = ref(false)
  const error = ref<string | null>(null)

  // --- Phone number actions ---

  async function fetchPhoneNumbers(orgId: string, offset = 0, limit = 20) {
    loading.value = true
    error.value = null
    try {
      const res = await listPhoneNumbers(orgId, offset, limit)
      phoneNumbers.value = res.phone_numbers
      phoneTotal.value = res.total
    } catch (e) {
      error.value = e instanceof Error ? e.message : String(e)
    } finally {
      loading.value = false
    }
  }

  async function addPhoneNumber(
    orgId: string,
    req: CreatePhoneNumberRequest,
  ): Promise<WhatsAppPhoneNumber> {
    const phone = await createPhoneNumber(orgId, req)
    phoneNumbers.value.push(phone)
    phoneTotal.value += 1
    return phone
  }

  async function removePhoneNumber(orgId: string, phoneId: string): Promise<void> {
    await deletePhoneNumber(orgId, phoneId)
    phoneNumbers.value = filter(phoneNumbers.value, (p) => p.id !== phoneId)
    phoneTotal.value -= 1
  }

  // --- Call actions ---

  async function fetchCalls(orgId: string, offset = 0, limit = 20) {
    loading.value = true
    error.value = null
    try {
      const res = await listCalls(orgId, offset, limit)
      calls.value = res.calls
      callTotal.value = res.total
    } catch (e) {
      error.value = e instanceof Error ? e.message : String(e)
    } finally {
      loading.value = false
    }
  }

  async function fetchCall(orgId: string, callId: string) {
    loading.value = true
    error.value = null
    try {
      activeCall.value = await getCall(orgId, callId)
    } catch (e) {
      error.value = e instanceof Error ? e.message : String(e)
    } finally {
      loading.value = false
    }
  }

  async function startCall(orgId: string, req: InitiateCallRequest): Promise<WhatsAppCall> {
    const call = await initiateCall(orgId, req)
    calls.value.unshift(call)
    callTotal.value += 1
    activeCall.value = call
    return call
  }

  async function endCall(orgId: string, callId: string): Promise<WhatsAppCall> {
    const call = await updateCallState(orgId, callId, 'ended' as CallState)
    activeCall.value = call
    // Update the call in the calls list
    const idx = calls.value.findIndex((c) => c.id === callId)
    if (idx !== -1) {
      calls.value[idx] = call
    }
    return call
  }

  // --- Bridge actions ---

  async function fetchBridgeStatus(orgId: string, callId: string) {
    try {
      const res = await getBridgeStatus(orgId, callId)
      currentBridge.value = res.bridge
    } catch {
      currentBridge.value = null
    }
  }

  async function fetchActiveBridges(orgId: string) {
    try {
      bridges.value = await listActiveBridges(orgId)
    } catch (e) {
      error.value = e instanceof Error ? e.message : String(e)
    }
  }

  function clearActiveCall() {
    activeCall.value = null
    currentBridge.value = null
  }

  return {
    // Phone numbers
    phoneNumbers,
    phoneTotal,
    fetchPhoneNumbers,
    addPhoneNumber,
    removePhoneNumber,

    // Calls
    calls,
    callTotal,
    activeCall,
    fetchCalls,
    fetchCall,
    startCall,
    endCall,

    // Bridges
    bridges,
    currentBridge,
    fetchBridgeStatus,
    fetchActiveBridges,

    // Shared
    loading,
    error,
    clearActiveCall,
  }
})

import { defineStore } from 'pinia'
import { ref } from 'vue'
import { filter } from 'remeda'
import {
  listVoiceSessions,
  getVoiceSession,
  createVoiceSession,
  updateVoiceSessionState,
  generateVoiceToken,
  listVoiceTurns,
  appendVoiceTurn,
  type VoiceSession,
  type VoiceSessionState,
  type VoiceTurn,
  type VoiceTokenResponse,
  type CreateVoiceSessionRequest,
  type AppendVoiceTurnRequest,
} from '../api/voice-sessions'

export const useVoiceSessionsStore = defineStore('voice-sessions', () => {
  const sessions = ref<VoiceSession[]>([])
  const currentSession = ref<VoiceSession | null>(null)
  const turns = ref<VoiceTurn[]>([])
  const total = ref(0)
  const loading = ref(false)
  const error = ref<string | null>(null)
  const pollingHandle = ref<ReturnType<typeof setInterval> | null>(null)

  async function fetchSessions(orgId: string, offset = 0, limit = 20) {
    loading.value = true
    error.value = null
    try {
      const res = await listVoiceSessions(orgId, offset, limit)
      sessions.value = res.sessions
      total.value = res.total
    } catch (e) {
      error.value = e instanceof Error ? e.message : String(e)
    } finally {
      loading.value = false
    }
  }

  async function fetchSession(orgId: string, sessionId: string) {
    loading.value = true
    error.value = null
    try {
      currentSession.value = await getVoiceSession(orgId, sessionId)
    } catch (e) {
      error.value = e instanceof Error ? e.message : String(e)
    } finally {
      loading.value = false
    }
  }

  async function create(
    orgId: string,
    req: CreateVoiceSessionRequest,
  ): Promise<VoiceSession> {
    const session = await createVoiceSession(orgId, req)
    sessions.value.push(session)
    total.value += 1
    return session
  }

  async function updateState(
    orgId: string,
    sessionId: string,
    state: VoiceSessionState,
  ): Promise<VoiceSession> {
    const session = await updateVoiceSessionState(orgId, sessionId, state)
    currentSession.value = session
    sessions.value = sessions.value.map((s) =>
      s.id === sessionId ? session : s,
    )
    return session
  }

  async function getToken(
    orgId: string,
    sessionId: string,
  ): Promise<VoiceTokenResponse> {
    return generateVoiceToken(orgId, sessionId)
  }

  async function fetchTurns(orgId: string, sessionId: string) {
    error.value = null
    try {
      const res = await listVoiceTurns(orgId, sessionId)
      turns.value = res.turns
    } catch (e) {
      error.value = e instanceof Error ? e.message : String(e)
    }
  }

  async function addTurn(
    orgId: string,
    sessionId: string,
    req: AppendVoiceTurnRequest,
  ): Promise<VoiceTurn> {
    const turn = await appendVoiceTurn(orgId, sessionId, req)
    turns.value.push(turn)
    return turn
  }

  function startPolling(orgId: string, sessionId: string) {
    stopPolling()
    pollingHandle.value = setInterval(async () => {
      try {
        const [session, turnRes] = await Promise.all([
          getVoiceSession(orgId, sessionId),
          listVoiceTurns(orgId, sessionId),
        ])
        currentSession.value = session
        turns.value = turnRes.turns
        sessions.value = sessions.value.map((s) =>
          s.id === sessionId ? session : s,
        )
        if (session.state === 'ended') {
          stopPolling()
        }
      } catch {
        /* polling errors are non-fatal */
      }
    }, 5000)
  }

  function stopPolling() {
    if (pollingHandle.value) {
      clearInterval(pollingHandle.value)
      pollingHandle.value = null
    }
  }

  function clearSession() {
    currentSession.value = null
    turns.value = []
    stopPolling()
  }

  function removeSession(sessionId: string) {
    sessions.value = filter(sessions.value, (s) => s.id !== sessionId)
    total.value = Math.max(0, total.value - 1)
    if (currentSession.value?.id === sessionId) {
      clearSession()
    }
  }

  return {
    sessions,
    currentSession,
    turns,
    total,
    loading,
    error,
    pollingHandle,
    fetchSessions,
    fetchSession,
    create,
    updateState,
    getToken,
    fetchTurns,
    addTurn,
    startPolling,
    stopPolling,
    clearSession,
    removeSession,
  }
})

