// Package repository_test contains integration tests for the repository layer.
package repository_test

import (
	"context"
	"testing"

	"github.com/google/uuid"
	"github.com/ravencloak-org/Raven/internal/repository"
	"github.com/ravencloak-org/Raven/internal/testutil"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestRLS_CrossOrgKB_ReturnsZeroRows verifies that org-B cannot read
// knowledge bases that belong to org-A, even when using the same workspace ID.
func TestRLS_CrossOrgKB_ReturnsZeroRows(t *testing.T) {
	if testing.Short() {
		t.Skip("skipping RLS integration test in short mode")
	}

	pool := testutil.NewTestDB(t)
	ctx := context.Background()

	orgA := uuid.NewString()
	orgB := uuid.NewString()
	wsID := uuid.NewString()
	slug := uuid.NewString()[:8]

	kbRepo := repository.NewKBRepository(pool)

	// Create a KB for org-A using a raw transaction.
	txA, err := pool.Begin(ctx)
	require.NoError(t, err)
	_, err = txA.Exec(ctx, "SELECT set_config('app.current_org_id', $1, true)", orgA)
	require.NoError(t, err)
	kb, err := kbRepo.Create(ctx, txA, orgA, wsID, "Org-A KB", slug, "")
	require.NoError(t, err)
	require.NoError(t, txA.Commit(ctx))
	require.NotEmpty(t, kb.ID)

	// Verify org-A can read its own KB.
	txVerifyA, err := pool.Begin(ctx)
	require.NoError(t, err)
	_, err = txVerifyA.Exec(ctx, "SELECT set_config('app.current_org_id', $1, true)", orgA)
	require.NoError(t, err)
	kbsA, err := kbRepo.ListByWorkspace(ctx, txVerifyA, orgA, wsID)
	require.NoError(t, err)
	assert.Len(t, kbsA, 1, "org-A must see its own KB")
	_ = txVerifyA.Rollback(ctx)

	// Verify org-B cannot see org-A's KB (RLS isolation).
	txB, err := pool.Begin(ctx)
	require.NoError(t, err)
	_, err = txB.Exec(ctx, "SELECT set_config('app.current_org_id', $1, true)", orgB)
	require.NoError(t, err)
	kbsB, err := kbRepo.ListByWorkspace(ctx, txB, orgA, wsID)
	require.NoError(t, err)
	assert.Empty(t, kbsB, "org-B must not see org-A's knowledge bases (RLS violation)")
	_ = txB.Rollback(ctx)
}

// TestRLS_CrossOrgKB_GetByID_ReturnsError verifies that org-B cannot fetch
// a specific KB that belongs to org-A by its ID.
func TestRLS_CrossOrgKB_GetByID_ReturnsError(t *testing.T) {
	if testing.Short() {
		t.Skip("skipping RLS integration test in short mode")
	}

	pool := testutil.NewTestDB(t)
	ctx := context.Background()

	orgA := uuid.NewString()
	orgB := uuid.NewString()
	wsID := uuid.NewString()
	slug := uuid.NewString()[:8]

	kbRepo := repository.NewKBRepository(pool)

	// Create a KB for org-A.
	txA, err := pool.Begin(ctx)
	require.NoError(t, err)
	_, err = txA.Exec(ctx, "SELECT set_config('app.current_org_id', $1, true)", orgA)
	require.NoError(t, err)
	kb, err := kbRepo.Create(ctx, txA, orgA, wsID, "Secret KB", slug, "")
	require.NoError(t, err)
	require.NoError(t, txA.Commit(ctx))

	// org-B tries to fetch org-A's KB by ID — RLS must prevent access.
	txB, err := pool.Begin(ctx)
	require.NoError(t, err)
	_, err = txB.Exec(ctx, "SELECT set_config('app.current_org_id', $1, true)", orgB)
	require.NoError(t, err)
	_, err = kbRepo.GetByID(ctx, txB, orgA, kb.ID)
	assert.Error(t, err, "org-B must not be able to fetch org-A's KB by ID (RLS violation)")
	_ = txB.Rollback(ctx)
}

// TestRLS_MigrationVersion_AllApplied verifies all migrations applied after NewTestDB.
func TestRLS_MigrationVersion_AllApplied(t *testing.T) {
	if testing.Short() {
		t.Skip("skipping migration version test in short mode")
	}

	pool := testutil.NewTestDB(t)
	ctx := context.Background()

	// All 32 SQL migrations must be applied.
	var maxVersion int64
	err := pool.QueryRow(ctx,
		"SELECT MAX(version_id) FROM goose_db_version WHERE is_applied = true",
	).Scan(&maxVersion)
	require.NoError(t, err)
	assert.EqualValues(t, 32, maxVersion, "all 32 migrations must be applied cleanly")

	// Spot-check critical tables exist.
	for _, table := range []string{
		"organizations", "workspaces", "knowledge_bases",
		"documents", "chunks", "chat_sessions", "chat_messages", "api_keys",
	} {
		var count int
		err := pool.QueryRow(ctx,
			"SELECT count(*) FROM information_schema.tables WHERE table_name = $1 AND table_schema = 'public'",
			table,
		).Scan(&count)
		require.NoError(t, err)
		assert.Equal(t, 1, count, "table %s must exist after migrations", table)
	}
}

// Package testutil provides shared helpers for Go tests including database containers,
// fixture factories, and gRPC stub implementations.
package testutil

import (
	"context"
	"database/sql"
	"fmt"
	"path/filepath"
	"runtime"
	"testing"
	"time"

	"github.com/jackc/pgx/v5/pgxpool"
	_ "github.com/lib/pq" // register postgres driver for goose migrations
	"github.com/pressly/goose/v3"
	"github.com/stretchr/testify/require"
	"github.com/testcontainers/testcontainers-go"
	"github.com/testcontainers/testcontainers-go/wait"
)

// NewTestDB spins up a real PostgreSQL container using pgvector, runs all migrations,
// and returns a pool. Container is terminated when t ends.
func NewTestDB(t *testing.T) *pgxpool.Pool {
	t.Helper()
	ctx := context.Background()

	req := testcontainers.ContainerRequest{
		Image:        "pgvector/pgvector:pg17",
		ExposedPorts: []string{"5432/tcp"},
		Env: map[string]string{
			"POSTGRES_USER":     "raven_test",
			"POSTGRES_PASSWORD": "raven_test_pass",
			"POSTGRES_DB":       "raven_test",
		},
		WaitingFor: wait.ForLog("database system is ready to accept connections").
			WithOccurrence(2).
			WithStartupTimeout(90 * time.Second),
	}

	container, err := testcontainers.GenericContainer(ctx, testcontainers.GenericContainerRequest{
		ContainerRequest: req,
		Started:          true,
	})
	require.NoError(t, err, "start postgres container")
	t.Cleanup(func() { _ = container.Terminate(ctx) })

	host, err := container.Host(ctx)
	require.NoError(t, err)

	port, err := container.MappedPort(ctx, "5432")
	require.NoError(t, err)

	connStr := fmt.Sprintf(
		"host=%s port=%s user=raven_test password=raven_test_pass dbname=raven_test sslmode=disable",
		host, port.Port(),
	)

	// Wait for DB to be fully ready.
	var db *sql.DB
	db, err = sql.Open("postgres", connStr)
	require.NoError(t, err)
	for i := 0; i < 30; i++ {
		if pingErr := db.PingContext(ctx); pingErr == nil {
			break
		}
		time.Sleep(time.Second)
	}
	require.NoError(t, db.PingContext(ctx), "database must be reachable")

	RunMigrations(t, db)
	_ = db.Close()

	pgxConnStr := fmt.Sprintf(
		"postgres://raven_test:raven_test_pass@%s:%s/raven_test?sslmode=disable",
		host, port.Port(),
	)
	pool, err := pgxpool.New(ctx, pgxConnStr)
	require.NoError(t, err)
	t.Cleanup(pool.Close)

	return pool
}

// RunMigrations applies all goose migrations from the repo migrations/ dir.
func RunMigrations(t *testing.T, db *sql.DB) {
	t.Helper()

	// Resolve migrations dir relative to this file: internal/testutil/ -> repo root/migrations/
	_, filename, _, ok := runtime.Caller(0)
	if !ok {
		t.Fatal("runtime.Caller failed to retrieve file path")
	}
	migrationsDir := filepath.Join(filepath.Dir(filename), "..", "..", "migrations")

	if err := goose.SetDialect("postgres"); err != nil {
		t.Fatalf("goose.SetDialect: %v", err)
	}
	if err := goose.Up(db, migrationsDir); err != nil {
		t.Fatalf("goose.Up: %v", err)
	}
}

package repository

import (
	"context"
	"fmt"

	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/ravencloak-org/Raven/internal/model"
)

// KBRepository handles database operations for knowledge bases.
// All operations use a pgx.Tx with org_id set for RLS enforcement.
type KBRepository struct {
	pool *pgxpool.Pool
}

// NewKBRepository creates a new KBRepository.
func NewKBRepository(pool *pgxpool.Pool) *KBRepository {
	return &KBRepository{pool: pool}
}

const kbColumns = `id, org_id, workspace_id, name, slug,
	COALESCE(description, '') AS description, settings, status, created_at, updated_at`

func scanKB(row pgx.Row) (*model.KnowledgeBase, error) {
	var kb model.KnowledgeBase
	err := row.Scan(
		&kb.ID,
		&kb.OrgID,
		&kb.WorkspaceID,
		&kb.Name,
		&kb.Slug,
		&kb.Description,
		&kb.Settings,
		&kb.Status,
		&kb.CreatedAt,
		&kb.UpdatedAt,
	)
	if err != nil {
		return nil, err
	}
	return &kb, nil
}

// Create inserts a new knowledge base within a workspace transaction.
func (r *KBRepository) Create(ctx context.Context, tx pgx.Tx, orgID, wsID, name, slug, description string) (*model.KnowledgeBase, error) {
	row := tx.QueryRow(ctx,
		`INSERT INTO knowledge_bases (org_id, workspace_id, name, slug, description)
		 VALUES ($1, $2, $3, $4, NULLIF($5, ''))
		 RETURNING `+kbColumns,
		orgID, wsID, name, slug, description,
	)
	kb, err := scanKB(row)
	if err != nil {
		return nil, fmt.Errorf("KBRepository.Create: %w", err)
	}
	return kb, nil
}

// GetByID fetches an active KB by its primary key.
func (r *KBRepository) GetByID(ctx context.Context, tx pgx.Tx, orgID, kbID string) (*model.KnowledgeBase, error) {
	row := tx.QueryRow(ctx,
		`SELECT `+kbColumns+`
		 FROM knowledge_bases
		 WHERE id = $1 AND org_id = $2 AND status = 'active'`,
		kbID, orgID,
	)
	kb, err := scanKB(row)
	if err != nil {
		return nil, fmt.Errorf("KBRepository.GetByID: %w", err)
	}
	return kb, nil
}

// ListByWorkspace returns all active KBs for a workspace.
func (r *KBRepository) ListByWorkspace(ctx context.Context, tx pgx.Tx, orgID, wsID string) ([]model.KnowledgeBase, error) {
	rows, err := tx.Query(ctx,
		`SELECT `+kbColumns+`
		 FROM knowledge_bases
		 WHERE org_id = $1 AND workspace_id = $2 AND status = 'active'
		 ORDER BY created_at`,
		orgID, wsID,
	)
	if err != nil {
		return nil, fmt.Errorf("KBRepository.ListByWorkspace: %w", err)
	}
	defer rows.Close()

	var kbs []model.KnowledgeBase
	for rows.Next() {
		var kb model.KnowledgeBase
		if err := rows.Scan(&kb.ID, &kb.OrgID, &kb.WorkspaceID, &kb.Name, &kb.Slug,
			&kb.Description, &kb.Settings, &kb.Status, &kb.CreatedAt, &kb.UpdatedAt); err != nil {
			return nil, fmt.Errorf("KBRepository.ListByWorkspace scan: %w", err)
		}
		kbs = append(kbs, kb)
	}
	return kbs, rows.Err()
}

// Update applies partial updates to a knowledge base.
func (r *KBRepository) Update(ctx context.Context, tx pgx.Tx, orgID, kbID string, name, description *string, settings map[string]any) (*model.KnowledgeBase, error) {
	row := tx.QueryRow(ctx,
		`UPDATE knowledge_bases
		 SET
		   name        = COALESCE($3, name),
		   description = COALESCE($4, description),
		   settings    = CASE WHEN $5::jsonb IS NOT NULL THEN $5::jsonb ELSE settings END
		 WHERE id = $1 AND org_id = $2 AND status = 'active'
		 RETURNING `+kbColumns,
		kbID, orgID, name, description, settings,
	)
	kb, err := scanKB(row)
	if err != nil {
		return nil, fmt.Errorf("KBRepository.Update: %w", err)
	}
	return kb, nil
}

// Archive sets a knowledge base status to 'archived' (soft delete).
func (r *KBRepository) Archive(ctx context.Context, tx pgx.Tx, orgID, kbID string) error {
	tag, err := tx.Exec(ctx,
		`UPDATE knowledge_bases SET status = 'archived' WHERE id = $1 AND org_id = $2`,
		kbID, orgID,
	)
	if err != nil {
		return fmt.Errorf("KBRepository.Archive: %w", err)
	}
	if tag.RowsAffected() == 0 {
		return fmt.Errorf("KBRepository.Archive: knowledge base %s not found", kbID)
	}
	return nil
}

